import numpy as np
from numba import njit, prange

@njit(parallel=True, cache=True)
def _outer_numba(vec1, vec2):
    n = len(vec1)
    m = len(vec2)
    result = np.empty((n, m), dtype=np.float64)
    for i in prange(n):
        vi = vec1[i]
        for j in range(m):
            result[i, j] = vi * vec2[j]
    return result

@njit(cache=True)
def _outer_numba_seq(vec1, vec2):
    n = len(vec1)
    m = len(vec2)
    result = np.empty((n, m), dtype=np.float64)
    for i in range(n):
        vi = vec1[i]
        for j in range(m):
            result[i, j] = vi * vec2[j]
    return result

class Solver:
    def __init__(self):
        # Pre-compile numba functions
        v = np.array([1.0, 2.0])
        _outer_numba(v, v)
        _outer_numba_seq(v, v)

    def solve(self, problem, **kwargs):
        vec1, vec2 = problem
        n = len(vec1)
        if n > 64:
            return _outer_numba(vec1, vec2)
        else:
            return vec1[:, None] * vec2[None, :]
