import numpy as np
import torch

torch.set_num_threads(4)

class Solver:
    def __init__(self):
        # Warm up torch
        v = torch.from_numpy(np.array([1.0, 2.0]))
        torch.ger(v, v).numpy()

    def solve(self, problem, **kwargs):
        vec1, vec2 = problem
        n = len(vec1)
        if 50 < n <= 2000:
            v1 = torch.from_numpy(np.ascontiguousarray(vec1, dtype=np.float64))
            v2 = torch.from_numpy(np.ascontiguousarray(vec2, dtype=np.float64))
            return torch.ger(v1, v2).numpy()
        return np.multiply.outer(vec1, vec2)
